import{_ as a,o as t,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Web Basic Integration","description":"","frontmatter":{"title":"Web Basic Integration","slug":"web-basic-integration"},"headers":[],"relativePath":"developer-hub/web-basic-integration.md","filePath":"developer-hub/web-basic-integration.md"}'),i={name:"developer-hub/web-basic-integration.md"};function o(s,e,d,l,c,h){return t(),n("div",null,[...e[0]||(e[0]=[r(`<p>This page outlines the steps required to integrate the Branch Web SDK. At the end, you will be ready to send <a href="./track-branch-events.html">Branch Events</a> and use <a href="./creating-a-deep-link.html">Branch Deep Links</a>.</p><table tabindex="0"><thead><tr><th>GitHub</th><th>SDK Size</th><th>Speed</th></tr></thead><tbody><tr><td>&amp;lt;<a href="https://github.com/BranchMetrics/web-branch-deep-linking-attribution/releases%5C&amp;gt" target="_blank" rel="noreferrer">https://github.com/BranchMetrics/web-branch-deep-linking-attribution/releases\\&amp;gt</a>;</td><td>50kb</td><td>Median 80ms to 250ms</td></tr></tbody></table><p><strong>Note</strong>: On iOS 14 in Safari, you will likely see <code>branch.io</code> listed as &quot;blocked&quot; with the new visibility. This is expected, and simply means that cookies from <code>branch.io</code> are blocked. No web functionality or tracking will be impacted. Branch uses a different domain for managing cookies.</p><h4 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h4><p>The Branch Web SDK requires native browser JavaScript. No 3rd party libraries are needed to make use of the Branch Web SDK, as it is 100% native JavaScript.</p><h4 id="browser-support" tabindex="-1">Browser Support <a class="header-anchor" href="#browser-support" aria-label="Permalink to &quot;Browser Support&quot;">​</a></h4><p>The Branch Web SDK has been tested in all modern browsers with <code>sessionStorage</code> capability.</p><table tabindex="0"><thead><tr><th>Chrome</th><th>Firefox</th><th>Safari</th><th>IE</th></tr></thead><tbody><tr><td>✔</td><td>✔</td><td>✔</td><td>9, 10, 11</td></tr></tbody></table><h4 id="branch-journeys-escaped-keys-and-values" tabindex="-1">Branch Journeys Escaped Keys and Values <a class="header-anchor" href="#branch-journeys-escaped-keys-and-values" aria-label="Permalink to &quot;Branch Journeys Escaped Keys and Values&quot;">​</a></h4><p>Data returned from Branch Journeys event handlers contains escaped keys and values. This is true in Branch Web SDK versions 2.48.0 and older.</p><p>Characters targeted for escaping include:</p><ul><li><code>&quot;</code></li><li><code>&#39;</code></li><li><code>&amp;</code></li><li><code>&lt;</code></li><li><code>&gt;</code></li></ul><p>These characters are escaped to their corresponding HTML entities.</p><p>Additionally, URLs (in both keys and values) will be URI encoded.</p><p>Developers using Branch Web SDK versions 2.49.0 and up will notice values in Branch Journeys link data escaped with the same rules as above. Keys will not be escaped.</p><h2 id="_1-configure-branch" tabindex="-1">1. Configure Branch <a class="header-anchor" href="#_1-configure-branch" aria-label="Permalink to &quot;1. Configure Branch&quot;">​</a></h2><p>Start by configuring the Branch Dashboard for your application.</p><ol><li>On the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">App Settings</a> page of the Branch Dashboard, navigate to the <strong>General</strong> tab.</li><li>Enter your fallback URL for mobile devices that do not have a specified redirect:</li></ol><h2 id="_2-install-branch" tabindex="-1">2. Install Branch <a class="header-anchor" href="#_2-install-branch" aria-label="Permalink to &quot;2. Install Branch&quot;">​</a></h2><p>There are several ways you can reference or install the Branch Web SDK.</p><h4 id="script-tag-in-html" tabindex="-1">Script Tag in HTML <a class="header-anchor" href="#script-tag-in-html" aria-label="Permalink to &quot;Script Tag in HTML&quot;">​</a></h4><p>To reference the latest version of the Branch Web SDK, add the following to your HTML:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;!doctype html&gt;</span></span>
<span class="line"><span>&lt;html&gt;</span></span>
<span class="line"><span>   &lt;head&gt;</span></span>
<span class="line"><span>      &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;</span></span>
<span class="line"><span>      &lt;title&gt;&lt;/title&gt;</span></span>
<span class="line"><span>      &lt;script&gt;</span></span>
<span class="line"><span>         // Load Branch</span></span>
<span class="line"><span>         (function(b,r,a,n,c,h,_,s,d,k){if(!b[n]||!b[n]._q){for(;s&lt;_.length;)c(h,_[s++]);d=r.createElement(a);d.async=1;d.src=&quot;https://cdn.branch.io/branch-latest.min.js&quot;;k=r.getElementsByTagName(a)[0];k.parentNode.insertBefore(d,k);b[n]=h}})(window,document,&quot;script&quot;,&quot;branch&quot;,function(b,r){b[r]=function(){b._q.push([r,arguments])}},{_q:[],_v:1},&quot;addListener banner closeBanner closeJourney data deepview deepviewCta first init link logout removeListener setBranchViewData setIdentity track trackCommerceEvent logEvent disableTracking getBrowserFingerprintId crossPlatformIds lastAttributedTouchData setAPIResponseCallback qrCode setRequestMetaData setAPIUrl getAPIUrl setDMAParamsForEEA&quot;.split(&quot; &quot;), 0);</span></span>
<span class="line"><span>      &lt;/script&gt;</span></span>
<span class="line"><span>   &lt;/head&gt;</span></span>
<span class="line"><span>   &lt;body&gt;&lt;/body&gt;</span></span>
<span class="line"><span>&lt;/html&gt;</span></span></code></pre></div><p>If you want to reference a specific version of the Branch Web SDK, visit the Web Version History <a href="./web-version-history.html">page</a> for the CDN link, SRI hash, and initialization script.</p><h4 id="bower-package-manager" tabindex="-1">Bower Package Manager <a class="header-anchor" href="#bower-package-manager" aria-label="Permalink to &quot;Bower Package Manager&quot;">​</a></h4><p>To install the Branch Web SDK with Bower, use the following command:</p><p><code>bower install branch-sdk</code></p><h4 id="node-package-manager" tabindex="-1">Node Package Manager <a class="header-anchor" href="#node-package-manager" aria-label="Permalink to &quot;Node Package Manager&quot;">​</a></h4><p>To install the Branch Web SDK with NPM, use the following command:</p><p><code>npm install branch-sdk</code></p><h4 id="common-js-and-requirejs-compatibility" tabindex="-1">Common.JS and RequireJS Compatibility <a class="header-anchor" href="#common-js-and-requirejs-compatibility" aria-label="Permalink to &quot;Common.JS and RequireJS Compatibility&quot;">​</a></h4><p>In addition to working as a standalone library, the Branch Web SDK works great in CommonJS environments (browserify, webpack) as well as RequireJS environments (RequireJS/AMD).</p><p>Just use <code>require(&#39;branch&#39;)</code> or <code>define([&#39;branch&#39;], function(branch) { ... });</code> to get started!</p><h2 id="_3-initialize-branch" tabindex="-1">3. Initialize Branch <a class="header-anchor" href="#_3-initialize-branch" aria-label="Permalink to &quot;3. Initialize Branch&quot;">​</a></h2><p>To initialize Branch, use the <code>init()</code> method.</p><h4 id="basic-example-with-logging" tabindex="-1">Basic Example With Logging <a class="header-anchor" href="#basic-example-with-logging" aria-label="Permalink to &quot;Basic Example With Logging&quot;">​</a></h4><p>The <code>init()</code> method requires a Branch Key, which you can get from your account’s <a href="https://branch.dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Settings</a> page in the Branch Dashboard.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Replace key_live_YOUR_KEY_GOES_HERE with your Branch Key (live version)</span></span>
<span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, function(err, data) {</span></span>
<span class="line"><span>	console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><h4 id="example-with-additional-options" tabindex="-1">Example With Additional Options <a class="header-anchor" href="#example-with-additional-options" aria-label="Permalink to &quot;Example With Additional Options&quot;">​</a></h4><p>You can also use the <code>init()</code> method with special options:</p><table tabindex="0"><thead><tr><th>Key</th><th>Value</th><th>Type</th><th>Required</th></tr></thead><tbody><tr><td><code>branch_match_id</code></td><td>The current user&#39;s <code>browser-fingerprint-id</code>. The value of this parameter should be the same as the value of <code>?_branch_match_id</code> (automatically appended by Branch after a link click). <strong>Only necessary if</strong> <code>?_branch_match_id</code> is lost due to multiple redirects in your flow.</td><td><code>string</code></td><td>N</td></tr><tr><td><code>branch_view_id</code></td><td>If you would like to test how Branch Journeys render on your page before activating them, set the value of this parameter to the id of the view you are testing <strong>Only necessary if</strong> testing a view related to a Branch Journey.</td><td><code>string</code></td><td>N</td></tr><tr><td><code>no_journeys</code></td><td>When set to <code>true</code>, this option prevents Branch Journeys from appearing on the current page.</td><td><code>boolean</code></td><td>N</td></tr><tr><td><code>disable_entry_animation</code></td><td>When set to <code>true</code>, prevents a Branch Journeys entry animation.</td><td><code>boolean</code></td><td>N</td></tr><tr><td><code>disable_exit_animation</code></td><td>When set to <code>true</code>, prevents a Branch Journeys exit animation.</td><td><code>boolean</code></td><td>N</td></tr><tr><td><code>open_app</code></td><td>When set to <code>true</code>, Branch will try to open the app passively through Branch Journeys (as opposed to opening it upon user clicking). Default value is <code>false</code>.</td><td><code>boolean</code></td><td>N</td></tr><tr><td><code>nonce</code></td><td>A nonce value that will be included on any script or style tags Branch adds to your site. Used to allowlist these tags in your Content Security Policy.</td><td><code>string</code></td><td>N</td></tr></tbody></table><p>For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var options = { no_journeys: true };</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Replace key_live_YOUR_KEY_GOES_HERE with your Branch Key (live version)</span></span>
<span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, options, function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><h4 id="data-returned" tabindex="-1">Data Returned <a class="header-anchor" href="#data-returned" aria-label="Permalink to &quot;Data Returned&quot;">​</a></h4><p>The <code>data</code> object passed back by Branch includes the following fields:</p><table tabindex="0"><thead><tr><th>Key</th><th>Value</th><th>Type</th></tr></thead><tbody><tr><td><code>data_parsed</code></td><td>If the user was referred from a link and the link has associated data, then the data is passed in here.</td><td><code>object</code></td></tr><tr><td><code>has_app</code></td><td>Whether the user has the app installed already. This is based on Branch&#39;s persona data.</td><td><code>object</code></td></tr><tr><td><code>identity</code></td><td>Unique string that identifies the user. Originally set by the <code>setIdentity()</code> method.</td><td><code>string</code></td></tr><tr><td><code>referring_link</code></td><td>The referring link that was clicked, if available.</td><td><code>string</code></td></tr><tr><td><code>referring_identity</code></td><td>If the user was referred from a link and the link was created by a user with an identity in the Branch system, that identity is the <code>referring_identity</code>.</td><td><code>string</code></td></tr></tbody></table><h2 id="_4-validate-integration" tabindex="-1">4. Validate Integration <a class="header-anchor" href="#_4-validate-integration" aria-label="Permalink to &quot;4. Validate Integration&quot;">​</a></h2><p>It&#39;s important to validate your Branch Web SDK integration after you&#39;ve set it up, to make sure that data flows properly to the Branch Dashboard and you&#39;re able to start configuring Branch Deep Links and sending Branch Events.</p><p>Validation methods:</p><ol><li>The Overview tab in the <a href="https://dashboard.branch.io/integration" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>The Branch Web SDK&#39;s Integration Validation method.</li><li>The Branch Web SDK&#39;s Enable Logging method.</li><li>Branch&#39;s <a href="https://help.branch.io/docs/link-validator?highlight=link%20validator" target="_blank" rel="noreferrer">Link Validator tool</a>, which helps you confirm Branch Deep Link configuration, data, and routing.</li></ol><p>For additional testing scenarios and tools, visit the Web Testing <a href="./web-testing.html">page</a>.</p><p>If you&#39;re running into issues with your Branch Web SDK integration, start by looking at the Web Troubleshooting <a href="./web-troubleshooting.html">page</a>.</p>`,52)])])}const b=a(i,[["render",o]]);export{u as __pageData,b as default};
